function now() {
  return Date.now();
}

function randomId(bytes = 24) {
  return crypto.randomBytes(bytes).toString("hex");
}

function stableUserId(username) {
  const name = (username || "").trim().toLowerCase();
  return crypto.createHash("sha256").update("user:" + name).digest("hex").slice(0, 32);
}

// In-memory stores (replace with Redis/DB for production)
const sessionsByToken = new Map(); // token -> session
