function makeSession(username, meta = {}) {
  const cleanUsername = String(username || "").trim();
  if (!cleanUsername || cleanUsername.length > 24) return null;

  const userId = stableUserId(cleanUsername);
  const token = randomId(24);
  const session = {
    token,
    userId,
    username: cleanUsername,
    createdAt: now(),
    lastSeenAt: now(),
    expiresAt: now() + SESSION_TTL_MS,
    meta: {
      userAgent: meta.userAgent || null,
      ip: meta.ip || null,
    },
  };
  sessionsByToken.set(token, session);
  upsertUserTokenIndex(userId, token);
  return session;
}

